# Production Nginx config for api.mecsu.vn
# Requires: SSL cert at /etc/nginx/ssl/{fullchain,privkey}.pem

user  nginx;
worker_processes  auto;
error_log  /var/log/nginx/error.log warn;
pid        /var/run/nginx.pid;

events {
    worker_connections 1024;
    use epoll;
}

http {
    include      /etc/nginx/mime.types;
    default_type application/octet-stream;
    sendfile     on;
    tcp_nopush   on;
    tcp_nodelay  on;
    keepalive_timeout 65;
    server_tokens off;

    # ── Logging ─────────────────────────────────────────────────
    log_format main '$remote_addr "$request" $status $body_bytes_sent '
                    '$request_time "$http_x_request_id"';
    access_log /var/log/nginx/access.log main;

    # ── Compression ─────────────────────────────────────────────
    gzip on;
    gzip_types application/json text/plain application/octet-stream;
    gzip_min_length 1024;
    gzip_vary on;

    # ── Rate limit zones ─────────────────────────────────────────
    # geometry/generate and /variant — heavy work, strict limit
    limit_req_zone $binary_remote_addr zone=geo_generate:10m rate=20r/m;
    # geometry/hash — immutable, more generous (CDN should absorb most)
    limit_req_zone $binary_remote_addr zone=geo_hash:10m    rate=120r/m;
    # admin ingestion — very strict
    limit_req_zone $binary_remote_addr zone=admin:10m       rate=10r/m;
    # general API reads
    limit_req_zone $binary_remote_addr zone=general:10m     rate=60r/m;

    # ── Upstream ─────────────────────────────────────────────────
    upstream api_backend {
        server api:8000;
        keepalive 32;
    }

    # ── HTTP → HTTPS redirect ─────────────────────────────────────
    server {
        listen 80;
        server_name api.mecsu.vn;
        return 301 https://$host$request_uri;
    }

    # ── HTTPS API server ──────────────────────────────────────────
    server {
        listen 443 ssl http2;
        server_name api.mecsu.vn;

        ssl_certificate     /etc/nginx/ssl/fullchain.pem;
        ssl_certificate_key /etc/nginx/ssl/privkey.pem;
        ssl_protocols       TLSv1.2 TLSv1.3;
        ssl_ciphers         ECDHE-ECDSA-AES128-GCM-SHA256:ECDHE-RSA-AES128-GCM-SHA256:ECDHE-ECDSA-AES256-GCM-SHA384:ECDHE-RSA-AES256-GCM-SHA384;
        ssl_prefer_server_ciphers off;
        ssl_session_cache   shared:SSL:10m;
        ssl_session_timeout 1d;

        # ── Security headers ───────────────────────────────────
        add_header X-Frame-Options DENY always;
        add_header X-Content-Type-Options nosniff always;
        add_header Strict-Transport-Security "max-age=31536000; includeSubDomains" always;
        add_header Referrer-Policy "strict-origin-when-cross-origin" always;

        # ── Health / ready (no rate limit, no auth) ────────────
        location = /health { proxy_pass http://api_backend; }
        location = /ready  { proxy_pass http://api_backend; }
        location = /metrics {
            # Only allow from internal monitoring subnet
            allow 10.0.0.0/8;
            allow 172.16.0.0/12;
            deny all;
            proxy_pass http://api_backend;
        }

        # ── Geometry HASH — immutable, browser-cacheable ────────
        location ~ ^/api/v1/geometry/hash/ {
            limit_req zone=geo_hash burst=30 nodelay;
            limit_req_status 429;

            proxy_pass http://api_backend;
            proxy_set_header Host $host;
            proxy_set_header X-Real-IP $remote_addr;
            proxy_set_header X-Request-ID $request_id;
            proxy_hide_header Cache-Control;
            add_header Cache-Control "public, max-age=31536000, immutable" always;
        }

        # ── Geometry generate / variant ─────────────────────────
        location /api/v1/geometry/ {
            limit_req zone=geo_generate burst=5 nodelay;
            limit_req_status 429;

            proxy_pass http://api_backend;
            proxy_set_header Host $host;
            proxy_set_header X-Real-IP $remote_addr;
            proxy_set_header X-Request-ID $request_id;
            proxy_read_timeout 35s;
        }

        # ── Admin — vendor assets upload ────────────────────────
        location /api/v1/vendor-assets {
            limit_req zone=admin burst=3 nodelay;
            limit_req_status 429;
            client_max_body_size 110M;
            proxy_pass http://api_backend;
            proxy_set_header Host $host;
            proxy_read_timeout 120s;
        }

        # ── Admin — ingestion ───────────────────────────────────
        location /api/v1/ingest/ {
            limit_req zone=admin burst=3 nodelay;
            limit_req_status 429;
            proxy_pass http://api_backend;
            proxy_set_header Host $host;
        }

        # ── General API ─────────────────────────────────────────
        location /api/ {
            limit_req zone=general burst=20 nodelay;
            limit_req_status 429;
            proxy_pass http://api_backend;
            proxy_set_header Host $host;
            proxy_set_header X-Real-IP $remote_addr;
            proxy_set_header X-Request-ID $request_id;
        }

        # ── Serve pre-built FE static (optional) ────────────────
        location / {
            root /var/www/html;
            try_files $uri /index.html;
            add_header Cache-Control "public, max-age=3600";
        }
    }
}

# Local development Nginx — no TLS, relaxed limits
user  nginx;
worker_processes  1;
events { worker_connections 512; }

http {
    include /etc/nginx/mime.types;
    default_type application/octet-stream;

    limit_req_zone $binary_remote_addr zone=geo:5m rate=60r/m;

    upstream api_backend { server api:8000; }

    server {
        listen 8080;
        server_name localhost;

        location ~ ^/api/v1/geometry/hash/ {
            proxy_pass http://api_backend;
            add_header Cache-Control "public, max-age=3600";
        }
        location /api/ {
            limit_req zone=geo burst=20 nodelay;
            proxy_pass http://api_backend;
            proxy_set_header X-Request-ID $request_id;
        }
        location / { proxy_pass http://api_backend; }
    }
}
